(function(){'use strict';const CONFIG={homeUrl:'/',error404Url:'/lndex.html',debug:false};const SPIDER_KEYWORDS=['Baiduspider','Googlebot','bingbot','Sogou','360Spider','YandexBot','Applebot','Baiduspider-render',];const MOBILE_CORE=['Android','iPhone','iPod','webOS','BlackBerry','IEMobile','Opera Mini'];const TABLET_KEYWORDS=['iPad','Tablet','Silk-Accelerated','PlayBook'];function log(msg,data={}){if(CONFIG.debug){console.log('[设备检测]',msg,data)}}function isSpider(){const ua=navigator.userAgent||'';for(let keyword of SPIDER_KEYWORDS){if(ua.indexOf(keyword)!==-1)return true}return false}function checkCSSCapabilities(){const supportsHover=window.matchMedia('(hover: hover)').matches;const supportsTouch=window.matchMedia('(pointer: coarse)').matches;const supportsFinePointer=window.matchMedia('(pointer: fine)').matches;log('CSS媒体查询检测',{supportsHover,supportsTouch,supportsFinePointer});return{supportsHover,supportsTouch,supportsFinePointer,isLikelyPC:supportsHover&&supportsFinePointer}}function checkUserAgentData(){const result={available:false,platform:null,mobile:null,isPCPlatform:false};if(navigator.userAgentData){result.available=true;result.platform=navigator.userAgentData.platform||null;result.mobile=navigator.userAgentData.mobile||null;log('User-Agent Data',{platform:result.platform,mobile:result.mobile});const pcPlatforms=['Windows','macOS','Linux','Win32','MacIntel'];if(result.platform&&pcPlatforms.some(p=>result.platform.indexOf(p)!==-1)){result.isPCPlatform=true}if(result.mobile===false){result.isPCPlatform=true}}else{log('User-Agent Data不可用')}return result}function isRealMobile(){const ua=navigator.userAgent||'';const platform=navigator.platform||'';log('基础信息',{ua:ua.substring(0,150),platform:platform,userAgentLength:ua.length});for(let keyword of TABLET_KEYWORDS){if(ua.indexOf(keyword)!==-1){log('✅ 平板设备，放行');return true}}const cssCaps=checkCSSCapabilities();if(cssCaps.isLikelyPC){log('❌ CSS检测支持hover，判定为电脑（包括模拟器）');return false}const uaData=checkUserAgentData();if(uaData.available&&uaData.isPCPlatform){log('❌ User-Agent Data暴露电脑平台，判定为模拟器',{platform:uaData.platform,mobile:uaData.mobile});return false}let hasMobileUA=false;for(let keyword of MOBILE_CORE){if(ua.indexOf(keyword)!==-1){hasMobileUA=true;log('命中移动UA标识',{keyword});break}}if(!hasMobileUA){log('❌ 无移动UA标识');return false}if(ua.indexOf('Android')!==-1){if(platform==='Win32'||platform==='Win64'||platform==='MacIntel'){log('❌ Android UA但platform是电脑，判定为模拟');return false}const hasTouch='ontouchstart'in window||(navigator.maxTouchPoints&&navigator.maxTouchPoints>0);if(hasTouch&&!cssCaps.isLikelyPC&&!uaData.isPCPlatform){log('✅ Android设备通过所有检测，放行');return true}log('❌ Android设备未通过综合检测',{hasTouch,cssCaps,uaData});return false}if(ua.indexOf('iPhone')!==-1||ua.indexOf('iPod')!==-1){if(platform.indexOf('iPhone')!==-1||platform.indexOf('iOS')!==-1){log('✅ iOS设备platform正确，放行');return true}if(platform==='Win32'||platform==='Win64'||platform==='MacIntel'){log('❌ iOS UA但platform是电脑，判定为模拟');return false}if(!cssCaps.isLikelyPC){log('✅ iOS设备CSS检测通过，放行');return true}log('❌ iOS设备未通过检测');return false}const hasTouch='ontouchstart'in window||(navigator.maxTouchPoints&&navigator.maxTouchPoints>0);const dpr=window.devicePixelRatio||1;if(hasTouch&&!cssCaps.isLikelyPC&&dpr>=1.5&&dpr<=4){log('✅ 移动设备通过综合检测，放行');return true}log('❌ 未通过综合检测');return false}function checkAndRedirect(){log('=== 开始设备检测 ===',{timestamp:new Date().toISOString(),href:window.location.href});if(isSpider()){log('✅ 搜索引擎蜘蛛，放行');return}if(isRealMobile()){log('✅ 真实移动设备，正常访问当前页面');return}log('❌ 非真实移动设备，跳转404');window.location.replace(CONFIG.error404Url)}checkAndRedirect()})();